describe('Race Log — Loading skeleton', () => {
  it('shows skeleton while fetch is in-flight', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()

    cy.intercept('GET', `${LIST_EP}*`, (req) => {
      req.reply((res) => {
        res.setDelay(600)
        res.send({ statusCode: 200, body: { data: [entry1], message: 'ok' } })
      })
    }).as('getRaceLogDelayed')

    visitPage()

    // Skeleton is nested inside the table wrapper which is shown even during loading
    cy.get(`[id="${IDS.loading_skeleton}"]`).should('exist').and('be.visible')
    // List wrapper is also present while loading (table shows skeleton rows inside it)
    cy.get(`[id="${IDS.list}"]`).should('exist')
  })
})

